/* thumbnail-loader.compat.fixed.js (patched for multi-host, MARU engine)
   - Fetches Netlify Function feed: /.netlify/functions/feed?page=PAGEKEY
   - Fallback to /assets/hero/psom.json (array) filtered by page
   - Renders into ALL elements that have [data-psom-key] (not just the first)
*/
(function () {
  "use strict";

  var PAGEKEY_ATTR = "data-psom-key";
  var FEED_ENDPOINT = "/.netlify/functions/feed";

  function getHosts() {
    try { return Array.prototype.slice.call(document.querySelectorAll("[" + PAGEKEY_ATTR + "]")); }
    catch (e) { return []; }
  }

  function safeText(s){ return (s==null?"":String(s)).replace(/</g,"&lt;").replace(/>/g,"&gt;"); }

  function guessLang(){
    try{
      var l = (document.documentElement.getAttribute("lang") || "").trim();
      if (l) return l;
    }catch(e){}
    return "ko";
  }

  function mapItem(x){
    if (!x) return null;
    var img = x.img || x.image || x.thumbnail || "";
    var href = x.href || x.url || "#";
    return {
      title: safeText(x.title || x.name || x.label || ""),
      href: href,
      img: img,
      desc: safeText(x.desc || x.description || x.category || "")
    };
  }

  function renderInto(host, items){
    if (!host) return;
    var arr = Array.isArray(items) ? items : [];
    if (!arr.length) {
      host.innerHTML = '<div class="thumb-empty">No items</div>';
      return;
    }
    var html = arr.map(function(it){
      var s = mapItem(it) || { title:"", href:"#", img:"", desc:"" };
      var img = s.img ? ('<img loading="lazy" src="'+s.img+'" alt=""/>') : "";
      var dsc = s.desc ? ('<div class="d">'+s.desc+'</div>') : "";
      return (
        '<a class="thumb-card" href="'+(s.href||"#")+'" target="_blank" rel="noopener noreferrer">' +
          img +
          '<div class="t">'+(s.title||"")+'</div>' +
          dsc +
        '</a>'
      );
    }).join("");
    host.innerHTML = html;
  }

  function normalizeJson(json){
    if (!json) return [];
    if (Array.isArray(json)) return json;
    if (Array.isArray(json.items)) return json.items;
    if (json.data && Array.isArray(json.data)) return json.data;
    if (json.data && Array.isArray(json.data.items)) return json.data.items;
    return [];
  }

  function fetchFeed(pageKey){
    var url = FEED_ENDPOINT + "?page=" + encodeURIComponent(pageKey) + "&lang=" + encodeURIComponent(guessLang());
    try{
      if (window.IGDC_CORE && typeof window.IGDC_CORE.country === "function") {
        url += "&country=" + encodeURIComponent(window.IGDC_CORE.country());
      }
    }catch(e){}
    return fetch(url, { credentials: "omit" })
      .then(function(r){ if(!r.ok) throw new Error("HTTP_"+r.status); return r.json(); })
      .then(function(j){ return normalizeJson(j); });
  }

  function fetchFallback(){
    return fetch("/assets/hero/psom.json", { credentials: "omit" })
      .then(function(r){ if(!r.ok) throw new Error("HTTP_"+r.status); return r.json(); })
      .then(function(j){ return normalizeJson(j); });
  }

  function filterByPage(items, pageKey){
    var k = (pageKey||"").toLowerCase();
    return (Array.isArray(items)?items:[]).filter(function(it){
      var p = (it.page || it.pageKey || it.key || "").toLowerCase();
      return p === k;
    });
  }

  // cache by pageKey to avoid duplicate fetches
  var cache = Object.create(null);

  function loadForHost(host){
    var key = (host.getAttribute(PAGEKEY_ATTR) || "").trim();
    if (!key) return;
    if (!cache[key]) {
      cache[key] = fetchFeed(key).catch(function(){ return fetchFallback().then(function(all){ return filterByPage(all, key); }); });
    }
    cache[key].then(function(items){ renderInto(host, items); })
      .catch(function(){ renderInto(host, []); });
  }

  function init(){
    var hosts = getHosts();
    if (!hosts.length) return;
    hosts.forEach(loadForHost);
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", init);
  } else {
    init();
  }

  window.__THUMB_VERSION__ = "maru-multihost-20251223";
})();
